{
  "title": "عمر الهياكل",
  "group": "الأعمار",
  "options": [
    {
      "text": "يتجميع بنجاح",
      "hint": "الهياكل التي تحتوي على مراجع تحتاج إلى تعيينات عمر"
    },
    {
      "text": "خطأ: مفقود محدد العمر"
    },
    {
      "text": "خطأ: عدم تطابق العمر",
      "hint": "لم نحدد أي أعمار بعد"
    },
    {
      "text": "خطأ: مرجع غير صالح",
      "hint": "المراجع صالحة، لكن شيء آخر مفقود"
    }
  ],
  "objectives": [
    "فهم تعيينات العمر في تعريفات الهياكل",
    "تحديد متى تحتاج حقول الهيكل إلى معاملات عمر",
    "تطبيق تعيينات العمر بشكل صحيح في تنفيذات الهياكل"
  ],
  "questionProse": [
    "هل سيتجميع تعريف هذا الهيكل؟ لماذا أو لماذا لا؟"
  ],
  "hintsProse": [],
  "explanationProse": [
    "يفشل الكود لأن الهياكل التي تحتوي على مراجع يجب أن تحدد الأعمار. إليك طريقة الإصلاح:",
    "أنماط شائعة:",
    "أفضل الممارسات:\n      1. استخدم الأنواع المملوكة (String) عندما تحتاج إلى تخزين البيانات إلى أجل غير مسمى\n      2. استخدم المراجع عندما يكون عمر الهيكل أقصر بوضوح من عمر البيانات\n      3. فكر في عدة معاملات عمر عندما يمكن للمراجع أن تكون لها أعمار مختلفة\n      4. وثّق علاقات الأعمار في الهياكل المعقدة"
  ]
}
